import React from 'react';

import useSiteMetadata from '@hooks/UseSiteMetadata';

/**
 * React component to output SEO related meta / link HTML tags.
 * This component is imported in each of the pages.
 * @param {Object} prop - prop object passed to this component
 * @param {?string} [prop.title] - Page title
 * @param {?string} [prop.description] - Page description
 * @param {?string} [prop.featuredImage] - Path to featured image
 * @param {?string} [prop.urlPath] - URL path of the page
 */
export default function Seo({ title, description, featuredImage, urlPath, children }) {
	const {
		siteName,
		title: defaultTitle,
		description: defaultDescription,
		featuredImage: defaultFeaturedImage,
		siteUrl,
		favicon,
		themeColor,
	} = useSiteMetadata();

	const url = `${siteUrl}${urlPath || ''}`,
		seoTitle = title ? siteName + ' | ' + title : defaultTitle,
		seoDesc = description || defaultDescription,
		seoImg = `${siteUrl}${featuredImage || defaultFeaturedImage}`;
	//const theFavicon = `${siteUrl}${favicon}`;

	return (
		<>
			<title>{seoTitle}</title>
			<meta name="description" content={seoDesc} />
			<meta name="image" content={seoImg} />
			<link rel="icon" href={favicon} type="image/x-icon" />
			<link rel="canonical" href={url} />
			<meta name="theme-color" content={themeColor}></meta>
			<meta property="og:title" content={seoTitle} />
			<meta property="og:description" content={seoDesc} />
			<meta property="og:image" content={seoImg} />
			<meta property="og:url" content={url} />
			<script type="application/ld+json">{`{
"@context": "https://schema.org",
"@type": ["WebApplication","MobileApplication"],
"name": "Kaagzi",
"operatingSystem": ["Android", "iOS", "Windows"],
"applicationCategory": "FinanceApplication",
"installUrl": "https://kaagzi.in/app",
"aggregateRating": {
	"@type": "AggregateRating",
	"ratingValue": "4.9",
	"ratingCount": "1936"
},
"offers": {
	"@type": "Offer",
	"price": "75.00",
	"priceCurrency": "INR",
	"eligibleRegion": {
		"@type": "Country",
		"name": "IN"
	}
}
}`}</script>
			{children}
		</>
	);
}

